final:
module top_module (
    input a,
    input b,
    input c,
    output reg not_q
);
    always @(*) begin
        case ({a, b, c})
            3'b000: not_q = 1'b0;
            3'b110: not_q = 1'b0;
            3'b101: not_q = 1'b1;
            3'b111: not_q = 1'b1;
            3'b100: not_q = 1'b1;
            3'b010: not_q = 1'b0;
            3'b001: not_q = 1'b0;
            3'b011: not_q = 1'b0;
        endcase
    end
endmodule
